const LITERAL_DANGEROUS = [':(){ :|:& };:', 'rm -rf /', 'rm -rf /*', 'shutdown', 'reboot', 'halt', 'mkfs', 'dd if=/dev/zero', 'chmod -R 777 /', 'chown -R root:root /', 'rm.*--no-preserve-root'];
const REGEX_DANGEROUS = [/wget.*\|.*bash/i, /curl.*\|.*bash/i];

export function isCommandSafe(command: string): boolean {
  const lower = command.toLowerCase();
  if (LITERAL_DANGEROUS.some(p => lower.includes(p))) return false;
  if (REGEX_DANGEROUS.some(r => r.test(lower))) return false;
  return true;
}
